B.Z6=new A.dB("\ud83e\udd16","IA OnExotic","Tu asistente inteligente con acceso a todos los datos de OnExotic en tiempo real.",null)
B.YU=new A.dB("\ud83d\udcac","Qu\xe9 puedes preguntar",'Como CEO puedes preguntar:\n- "\xbfCu\xe1nto stock queda del Drop \xd1?"\n- "\xbfQu\xe9 tareas urgentes hay hoy?"\n- "\xbfQui\xe9n falt\xf3 esta semana?"\n- "Resume el estado de los dise\xf1os"',null)
B.Zh=new A.dB("\ud83d\udd12","Acceso seg\xfan tu rol","Cada rol solo puede consultar su \xe1rea:\n- Dise\xf1adora \u2192 sus dise\xf1os y briefs\n- RRHH \u2192 asistencia y equipo\n- Producci\xf3n \u2192 stock y proveedores\n- CEO \u2192 todo sin l\xedmites",null)
B.YT=new A.dB("\u26a1","Tips para mejores respuestas","S\xe9 espec\xedfico en tus preguntas. Usa las sugerencias r\xe1pidas de abajo para consultas frecuentes. Las respuestas son cortas y directas para ahorrar tiempo.","\xa1Empezar a usar!")
B.Ag=s([B.Z6,B.YU,B.Zh,B.YT],t.gG)
B.YL=new A.px(B.Ag,null)
B.YW=new A.dB("\ud83d\udc65","Tu equipo OnExotic","Aqu\xed gestionas a todos los miembros del equipo, sus roles, horarios y desempe\xf1o.",null)
B.Z8=new A.dB("\u2795","Agregar miembros (solo CEOs)","Toca + para invitar a un nuevo miembro. Llena sus datos: nombre, email, rol y horario. El miembro recibir\xe1 acceso a la app con los permisos de su rol autom\xe1ticamente.",null)
B.YY=new A.dB("\ud83d\udcca","Seguimiento de asistencia","Cada tarjeta muestra el % de asistencia mensual del miembro.\nVerde = excelente\nAmarillo = regular\nRojo = necesita atenci\xf3n",null)
B.Z4=new A.dB("\ud83d\udcb0","Sistema de bonos","Gestiona los bonos del equipo por trimestre desde la secci\xf3n Bonos. Solo CEOs y RRHH pueden crear y aprobar bonos.","\xa1Entendido!")
B.zJ=s([B.YW,B.Z8,B.YY,B.Z4],t.gG)
B.YM=new A.py(B.zJ,null)
B.Z2=new A.dB("\ud83d\udce6","Control de inventario","Aqu\xed controlas todo el stock de prendas OnExotic, organizado por drops y tallas.",null)
B.Z_=new A.dB("\u2795","Agregar productos","Toca + para agregar un producto nuevo. Puedes agregar el stock de todas las tallas de una sola vez. El SKU se genera autom\xe1ticamente.",null)
B.Zb=new A.dB("\ud83d\udea8","Alertas de stock","Cuando el stock baja del m\xednimo configurado, aparece una alerta roja arriba. T\xf3cala para ver qu\xe9 productos necesitas reordenar antes del pr\xf3ximo drop.",null)
B.Ze=new A.dB("\ud83d\uddc2\ufe0f","Organizaci\xf3n por drops","Filtra por drop para ver solo los productos de EXOTIC0, \xd1, Drop 003, etc. Crea nuevos drops con el bot\xf3n + Nuevo drop cuando planifiques una nueva colecci\xf3n.","\xa1Entendido!")
