B.YN=new A.py(B.A9,null)
B.Z0=new A.dB("\ud83d\udccb","Control de asistencia","Aqu\xed registras la asistencia a las reuniones diarias del equipo OnExotic. Las reuniones son todos los d\xedas a las 9:00 AM en el Showroom.",null)
B.Zd=new A.dB("\u2705","C\xf3mo marcar tu asistencia",'Al llegar a la reuni\xf3n, abre esta pantalla y toca "Marcar mi asistencia". Solo puedes hacerlo una vez por reuni\xf3n. Si no marcas, quedas como Pendiente.',null)
B.YZ=new A.dB("\ud83d\udc51","Si eres CEO","Como CEO puedes:\n- Crear nuevas reuniones con el bot\xf3n +\n- Ver el estado de todo el equipo\n- Marcar la asistencia de cualquier miembro\n- Ver el historial mensual de asistencia",null)
B.Z9=new A.dB("\ud83d\udcc5","Despu\xe9s de la asistencia","Una vez marcada tu asistencia, ve a Tareas para revisar y actualizar las pendientes del d\xeda.","\xa1Entendido!")
