B.YO=new A.py(B.CR,null)
B.Zc=new A.dB("\ud83c\udfa8","Flujo de dise\xf1os","Aqu\xed gestionas todo el proceso creativo de OnExotic, desde la idea hasta el producto final.",null)
B.Z3=new A.dB("\ud83d\udcdd","Paso 1: El Brief","Todo empieza con un Brief. El CEO crea un brief con: t\xedtulo, drop asociado, descripci\xf3n, colores de referencia, im\xe1genes e inspiraci\xf3n, tipograf\xeda y fecha l\xedmite de entrega.",null)
B.Zi=new A.dB("\ud83d\udd8c\ufe0f","Paso 2: Proceso y avance","La dise\xf1adora recibe el brief, inicia el proceso y sube avances para que el CEO pueda monitorear el progreso en tiempo real.",null)
B.Z5=new A.dB("\ud83d\udc41\ufe0f","Paso 3: Revisi\xf3n","Cuando la dise\xf1adora termina, env\xeda el dise\xf1o a revisi\xf3n. El CEO puede:\n\u2705 Aprobar \u2192 pasa a producci\xf3n\n\u274c Rechazar \u2192 la dise\xf1adora recibe feedback y sube una nueva versi\xf3n.",null)
B.Z1=new A.dB("\ud83d\udc55","Paso 4: Producci\xf3n e inventario",'Al aprobar un dise\xf1o, toca "Crear en inventario" para registrar las prendas con sus tallas y cantidades a producir. El dise\xf1o queda vinculado al producto en inventario.',"\xa1Entendido!")
B.zu=s([B.Zc,B.Z3,B.Zi,B.Z5,B.Z1],t.gG)
B.YP=new A.py(B.zu,null)
B.Za=new A.dB("\u2705","Gesti\xf3n de tareas","Aqu\xed viven todas las tareas del equipo OnExotic organizadas por \xe1rea y prioridad.",null)
B.Zj=new A.dB("\ud83c\udfaf","Prioridades","Cada tarea tiene una prioridad:\n\ud83d\udd34 Alta \u2192 hacer hoy sin falta\n\ud83d\udfe1 Media \u2192 esta semana\n\ud83d\udfe2 Baja \u2192 cuando haya tiempo\n\nFiltra por \xe1rea: Tech, Dise\xf1o, Marketing, Producci\xf3n, RRHH, Legal.",null)
B.YS=new A.dB("\u2795","Crear tareas (solo CEOs)","Como CEO puedes crear y asignar tareas a cualquier miembro del equipo. Toca el bot\xf3n + para crear una nueva.",null)
B.Z7=new A.dB("\ud83d\udd04","Despu\xe9s de las tareas","Si hay dise\xf1os pendientes de revisar, ve a Dise\xf1os. Si hay stock bajo en inventario, actual\xedzalo. Mant\xe9n las tareas al d\xeda para que el equipo funcione bien.","\xa1Entendido!")
